var V2PreviewBillingProfilesUpdate = resource.OperationSpec{
	Name:      "update",
	Path:      "/v2/billing/profiles/{id}",
	Method:    "POST",
	IsPreview: true,
	Summary:   "Update a Billing Profile",
	Params: map[string]*resource.ParamSpec{
		"default_payment_method": {
			Type:        "string",
			Description: "The ID of the payment method object.",
		},
		"display_name": {
			Type:        "string",
			Description: "A customer-facing name for the billing profile.\nMaximum length of 250 characters.\nTo remove the display_name from the object, set it to null in the request.",
		},
		"lookup_key": {
			Type:        "string",
			Description: "An internal key you can use to search for a particular billing profile. It must be unique among billing profiles for a given customer.\nMaximum length of 200 characters.\nTo remove the lookup_key from the object, set it to null in the request.",
		},
	},
}

var V2PreviewBillingProfilesList = resource.OperationSpec{
	Name:      "list",
	Path:      "/v2/billing/profiles",
	Method:    "GET",
	IsPreview: true,
	Summary:   "List Billing Profiles",
	Params: map[string]*resource.ParamSpec{
		"limit": {
			Type:        "integer",
			Description: "Optionally set the maximum number of results per page. Defaults to 10.",
		},
		"lookup_keys": {
			Type:        "array",
			Description: "Filter billing profiles by lookup keys. Mutually exclusive\nwith `customer` and `default_payment_method`.\nYou can specify up to 10 lookup_keys.",
			Required:    true,
		},
		"page": {
			Type:        "string",
			Description: "Opaque page token.",
		},
		"status": {
			Type:        "string",
			Description: "Filter billing profiles by status. Can be combined\nwith all other filters. If not provided, all billing profiles will be returned.",
			Enum: []resource.EnumSpec{
				{Value: "active"},
				{Value: "inactive"},
			},
		},
		"customer": {
			Type:        "string",
			Description: "Filter billing profiles by a customer. Mutually exclusive\nwith `lookup_keys` and `default_payment_method`.",
		},
		"default_payment_method": {
			Type:        "string",
			Description: "Filter billing profiles by a default payment method. Mutually exclusive\nwith `customer` and `lookup_keys`.",
		},
	},
}

